// Pick the first SAFE attachment to extract: PDF only, <= 10MB. Everything else
// (docx, images, archives, executables, oversized) is skipped → body fallback.
const atts = ((($('Inbound Mail Webhook').first().json.body) || {}).attachments) || [];
const MAX = 10 * 1024 * 1024;
const pick = atts.find(a => a && a.mimeType === 'application/pdf' && Number(a.size || 0) > 0 && Number(a.size || 0) <= MAX);
return [{ json: { r2Key: pick ? pick.r2Key : '', att_filename: pick ? (pick.filename || 'attachment.pdf') : '', has_att: !!pick } }];

const b = ($('Inbound Mail Webhook').first().json.body) || {};
// attachment text comes from "Extract from File" (runs with continueOnError; empty if no PDF)
let attText = '';
try { const e = $('Extract from File').first().json || {}; attText = String(e.text || e.data || e.extractedText || ''); } catch (err) {}
attText = attText.slice(0, 6000);
let fn = '';
try { fn = (($('Pick Attachment').first().json) || {}).att_filename || ''; } catch (err) {}
const sys = `You are an extraction service that pulls actionable items from an inbound message for the Gibbs family (kids: ronin, rory). The message may be a school notice, community flyer, bill, event, or general info, and may include an attached PDF. Output ONLY a JSON array (no markdown). Each item: {"type":"date|dues|assignment|event|site-pointer|info","title":string,"dueAt":ISO-8601 date or datetime or null,"student":"ronin|rory|both|unknown","actionRequired":boolean,"amount":string|null,"teacher":string|null,"class":string|null,"source_hint":short verbatim quote,"confidence":0..1,"originalFrom":string|null}. Resolve relative dates against the email date. If the body shows the email was forwarded (e.g. a "From:" header inside a quoted block), set originalFrom to that sender's email address; otherwise null. If nothing actionable, return [].`;
const bodyText = String(b.text || '').slice(0, 5000);
let user = `EMAIL DATE: ${b.date || ''}\nFROM: ${b.from || ''}\nSUBJECT: ${b.subject || ''}\nTO: ${b.envelopeTo || ''}\n\nBODY:\n${bodyText}`;
if (attText.trim()) user += `\n\n--- ATTACHED PDF (${fn}) ---\n${attText}`;
return [{ json: { model: 'qwen3-30b-instruct', temperature: 0.1, max_tokens: 1500, messages: [ { role: 'system', content: sys }, { role: 'user', content: user } ] } }];

const resp = $input.first().json;
let content = (((resp.choices || [])[0] || {}).message || {}).content || '';
content = content.replace(/```json/gi, '').replace(/```/g, '').trim();
const s = content.indexOf('['), e = content.lastIndexOf(']');
let arr = [];
if (s >= 0 && e > s) {
  try { arr = JSON.parse(content.slice(s, e + 1)); }
  catch (err) { arr = [{ type: 'info', title: 'PARSE_ERROR', source_hint: content.slice(0, 300), confidence: 0 }]; }
}
if (!Array.isArray(arr)) arr = [];
const src = ($('Inbound Mail Webhook').first().json.body) || {};
// stable per-EMAIL identity (msgId) — feeds the deterministic item_key computed
// below, the SINGLE SOURCE OF TRUTH the Store node upserts on. So re-processing/
// retries update rows in place (stable ids) rather than duplicating or re-minting.
const source_msg_id = String(src.messageId || `${src.from || ''}|${src.subject || ''}|${src.date || ''}`);
// normalized title slug: lowercase, non-alphanumerics -> '-', collapsed, first ~40 chars.
const slugify = (t) => String(t || '').toLowerCase().replace(/[^a-z0-9]+/g, '-').replace(/^-+|-+$/g, '').slice(0, 40);
return arr.map(r => {
  const type = r.type || 'info';
  const title = r.title || '';
  const due_at = r.dueAt || null;
  const student = r.student || 'unknown';
  const amount = r.amount || null;
  const course = r.class || null;
  // due_date = YYYY-MM-DD of due_at, '' when null (date portion verbatim, no TZ convert).
  const due_date = due_at ? String(due_at).slice(0, 10) : '';
  // plain TEXT composite — no md5, no crypto. slug for ALL items so two distinct
  // same-day items (same type|student|due_date) don't collapse.
  const item_key = [source_msg_id, type, student, due_date, amount || '', course || '', slugify(title)].join('|');
  return { json: {
    source_msg_id,
    type,
    title,
    due_at,
    student,
    action_required: r.actionRequired === true,
    amount,
    teacher: r.teacher || null,
    course,
    source_hint: r.source_hint || null,
    confidence: (typeof r.confidence === 'number' ? r.confidence : null),
    source_channel: src.envelopeTo || '',
    source_subject: src.subject || '',
    source_from: src.from || '',
    original_from: r.originalFrom || null,
    item_key
  } };
});

// Aggregate THIS run's item_keys (from Parse Records — the canonical source) into
// one array so the Cleanup node can drop this email's previous rows not in the new set.
// Read from Parse Records (not Store) so a no-op upsert still contributes its key.
const recs = $('Parse Records').all().map(i => i.json);
const source_msg_id = recs.length ? recs[0].source_msg_id : '';
const item_keys = recs.map(r => r.item_key).filter(Boolean);
return [{ json: { source_msg_id, item_keys } }];
